class Solution:
    def maxTotalValue(self, nums, k):
        n = len(nums)
        best = 0
        for l in range(n):
            mn = mx = nums[l]
            for r in range(l, n):
                if nums[r] < mn:
                    mn = nums[r]
                if nums[r] > mx:
                    mx = nums[r]
                if mx - mn > best:
                    best = mx - mn
        return best * k

